VALUES
  ('police-8b7f1efc-moex-00087', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '為防治性騷擾及保護被害人之權益，特制定性騷擾防治法，下列敘述何者正確？', '["中央主管機關為內政部", "屬權勢性騷擾以外之性騷擾事件者，得於知悉事件發生後1年內提出申訴", "屬權勢性騷擾事件者，得於知悉事件發生後2年內提出申訴", "性騷擾事件發生時被害人未成年者，得於成年後3年內提出申訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00088', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'essay', '數年前 A市、B市警察機關有少數幹部指示下屬對於舉發之交通違規標
示單（俗稱白單），修改違規內容，使違規者繳交較輕之罰鍰，或甚至不
開立舉發違反道路交通管理事件通知單（俗稱紅單），此行為已圖利違規
停車之人。該兩機關之涉案員警，經檢察官調查後，以貪污治罪條例起
訴達數十人，而相關權責警察機關也立即予以這些員警停職處分。就此
案例而言，舊有（案件發生時）的警察文化與倫理，你認為應如何改變，
避免再發生此類情事？另警察機關於檢察官起訴後立即將員警停職，是
否妥適，請就員警停職之法律條文與立法精神，申論之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00089', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'essay', '警察勤務條例第11 條第 1項明定勤區查察勤務方式「於警勤區內，由警
勤區員警執行之，以家戶訪查方式，擔任犯罪預防、為民服務及社會治
安調查等任務」。惟勤區查察之制度已經過多次之變革，請敘述有關我國
警勤區制度的歷史沿革？另再詳述目前警勤區訪查之對象與查訪應遵
守之事項？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00090', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '隨著全球數位化程度加深、新興科技逐漸普及，資通訊安全已位列全球前十重大風險，並成為國家 安全的關鍵環節。依警察機關資通安全實施規定，有關電子郵件之安全管制規定，下列何者錯誤？', '["屬於「密」等級以上之公文及資料，不得以電子郵件傳送", "使用者停職或離職後，應於3個月內刪除其郵件帳號", "使用者長期未收信，以致影響郵件伺服器正常運作時，基於業務需要得移除該帳號", "禁止以遠程終端機模擬形式開啟電子郵件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00091', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '機關組織以法律制定者，其內部單位之分工職掌，以處務規程定之，為中央行政機關組織基準法 第8條第1項前段之規定；爰此，內政部警政署為處理內部單位之分工職掌，定有內政部警政署 處務規程，下列有關該處務規程規定掌理事項之敘述何者錯誤？', '["特殊地區警備治安之規劃、督導，由保安組掌理", "社會治安調查之規劃、指導、蒐集及處理，由保防組掌理", "特種勤務之協調、聯繫及督導，由督察室掌理", "社區治安工作之協調推動、輔導、考核及評鑑，由行政組掌理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00092', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察機關為維護警察紀律、鍛鍊員警體能及充實其實務知能，應實施常年訓練；依警察常年訓練 辦法第4條規定，常年訓練區分為一般訓練及專案訓練，下列何者屬於專案訓練之性質？', '["業務訓練", "幹部訓練", "特定任務訓練", "組合訓練"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00093', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察官規係指中央與地方各級警察人員之官等、俸給、職務等階等相關事項之規範，為警察法第 3條第1項所定，由中央立法之事項，並制定有警察人員人事條例，下列有關該條例之總則規範 事項何者錯誤？', '["警察官、職分立，官受保障，職得調任，非依法不得免官或免職", "警察人員由內政部管理，或交由各直轄市政府、縣（市）政府管理", "擬任警察官前，其擬任機關、學校應就其個人品德、忠誠、素行經歷及身心健康狀況實施查核", "警察官等分為警監、警正、警佐。警監官等分為特、一、二、三、四階，警正及警佐官等各分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00094', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察人員人事條例，有關警察人員任官與任職之相關規定，下列敘述何者正確？', '["警正由內政部警政署核轉銓敘部銓敘審定合格後，報內政部任官", "警監及警正職務，由內政部遴任或報請行政院遴任", "警監由內政部核轉銓敘部銓敘審定合格後，逕予任官", "警正及警佐職務，由內政部遴任或交由直轄市政府遴任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00095', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '內政部警政署為端正警察風紀，建立優質警察文化，提升政府廉能形象，訂有端正警察風紀實施 規定；該規定將警察風紀區分為品操風紀及工作風紀，下列何者為工作風紀之要求？', '["嚴禁藉故推諉怠忽或無故延誤", "不接受不當飲宴、應酬及請託關說", "禁止涉足不妥當場所", "不發生不正常感情交往"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00096', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察為了保護社會安全並防止一切危害，其職權包括有協助偵查犯罪，執行搜索、扣押、拘提及 逮捕等作為，為保障警察人員之執勤安全，其職權更有使用警械；下列對於各級警察機關學校之 武器彈藥統籌調配等相關規定，何者敘述正確？', '["臺南市政府警察局之武器彈藥，由臺南市政府警察局自行編列預算", "新北市政府警察局武器彈藥之保養及修理，由新北市政府警察局自行編列預算", "基隆市警察局武器彈藥之保養及修理，由中央編列預算", "中央警察大學之武器彈藥，由中央編列預算"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
